package com.cho2hand.marketplace.entity.notification; import jakarta.persistence.*; import java.time.Instant;
@Entity @Table(name="notifications") public class Notification {@Id @GeneratedValue(strategy=GenerationType.IDENTITY) @Column(name="notification_id") private Long id; @Column(name="recipient_user_id") private Long recipientUserId; private String type; private String body; @Column(name="reference_path") private String referencePath; @Column(name="read_at") private Instant readAt; @Column(name="created_at") private Instant createdAt; @PrePersist void created(){createdAt=Instant.now();} public Long getId(){return id;} public Long getRecipientUserId(){return recipientUserId;} public String getType(){return type;} public String getBody(){return body;} public String getReferencePath(){return referencePath;} public Instant getReadAt(){return readAt;} public Instant getCreatedAt(){return createdAt;} public void setRecipientUserId(Long v){recipientUserId=v;} public void setType(String v){type=v;} public void setBody(String v){body=v;} public void setReferencePath(String v){referencePath=v;} public void touch(){createdAt=Instant.now();readAt=null;} public void markRead(){readAt=Instant.now();}}
